const rawList = $node["2. Extract Reel Data"].json["avtarList"] || "";

// 2. Clean the list: split by comma, trim whitespace, and remove empty values
const targetAvatars = rawList.split(',')
  .map(name => name.trim())
  .filter(name => name.length > 0);

// 3. Get all the input items (the list of image rows you provided)
const allRows = items.map(item => item.json);

// 4. Group data by Avatar Name
const grouped = {};

allRows.forEach(row => {
  const name = row["Avatar Name"];

  // Only process if this name exists in our target list
  if (targetAvatars.includes(name)) {
    if (!grouped[name]) {
      grouped[name] = {
        "Avatar Name": name,
        "Avatar Id": row["Avatar Id"],
        "Images": []
      };
    }

    // Construct the Google Drive download link
    const downloadLink = `https://drive.google.com/uc?export=download&id=${row["Image Id"]}`;

    grouped[name].Images.push({
      "Image Name": row["Image name"],
      "Download Link": downloadLink
    });
  }
});

// 5. Convert the grouped object back into an array for n8n output
return Object.values(grouped);

// Get all incoming items
const inputData = items.map(item => item.json);

// Extract names
const allNames = inputData.map(avatar => avatar["Avatar Name"]);

// Extract the "Front" or "Fallback" URLs
const referenceUrls = inputData.map(avatar => {
  const images = avatar["Images"] || [];

  // 1. Try to find the image that contains "front" (case-insensitive)
  const frontImage = images.find(img => 
    img["Image Name"].toLowerCase().includes('front')
  );

  // 2. If found, return its link. If not, take the first image link available.
  if (frontImage) {
    return frontImage["Download Link"];
  } else if (images.length > 0) {
    return images[0]["Download Link"]; // Random/First fallback
  }

  return null; // No images found at all
});

// NEW: Extract all URLs for each avatar as a list of lists
const elementUrls = inputData.map(avatar => {
  const images = avatar["Images"] || [];
  // Return an array of just the "Download Link" strings for this specific avatar
  return images.map(img => img["Download Link"]);
});

// Return a single object with the consolidated lists
return [{
  "Avatar Names": allNames,
  "Total Avatars": allNames.length,
  "Reference URLs": referenceUrls,
  "Element URLs": elementUrls // The list of lists containing all links
}];

